import React, { useState } from "react";

import { VscChevronLeft, VscChevronRight } from "react-icons/vsc";

import ehrhart from "../Assets/projets/ehrhartMockup.webp";
import arpege from "../Assets/projets/arpegeMockup.webp";
import findvalto from "../Assets/projets/findvaltoMockup.webp";

import '../styles/Work.css';


const Work = React.forwardRef((props, ref) => {
    const images = [ehrhart, arpege, findvalto];
    const [currentImage, setCurrentImage] = useState(0);
    const [isFullscreen, setIsFullscreen] = useState(false);
    return (
        <div ref={ref} className="contentPage" id="work" >
            <div className="title">Work</div>
            <div className="workContainer">
                <div className="caroussel">
                    <div className="arrowContainerL" onClick={() => {
                        if (currentImage > 0) {
                            setCurrentImage((currentImage - 1) % images.length);
                        } else {
                            setCurrentImage(images.length - 1);
                        }
                    }}>
                        <div className="arrowCircle" >
                            <VscChevronLeft className="arrowIcon" />
                        </div>
                    </div>
                    {
                        images?.map((image, index) => (
                            <div key={index} className="imgDiv" style={{
                                opacity: currentImage === index ? 1 : 0,
                                display: currentImage === index ? "flex" : "none"
                            }} onClick={() => setIsFullscreen(true)}>
                                <img className="imgCaroussel" src={image} alt="ehrhart" />
                            </div>
                        ))
                    }
                    <div className="arrowContainerR" onClick={() => {
                        setCurrentImage((currentImage + 1) % images.length)
                    }}>
                        <div className="arrowCircle">
                            <VscChevronRight className="arrowIcon" />
                        </div>
                    </div>

                    <div className="fullscreen"
                        style={{ opacity: isFullscreen ? 1 : 0, zIndex: isFullscreen ? 9999 : -1 }}
                        onClick={() => setIsFullscreen(false)}>
                        <img src={images[currentImage]} alt="fullscreen" className="fullscreenImg" />
                    </div>
                </div>
            </div>
        </div >
    )
});

export default Work;
