import React, { useState } from "react";
import anime from "animejs/lib/anime.es.js"

import { RiSendPlaneLine } from "react-icons/ri"


import '../styles/Contact.css';

function getWindowSize() {
    const { innerWidth, innerHeight } = window;
    return { innerWidth, innerHeight };
}

const Contact = React.forwardRef((props, ref) => {
    const animationRef = React.useRef(null);
    const [disableInput, setDisableInput] = useState(false);
    const [windowSize, setWindowSize] = useState(getWindowSize());


    React.useEffect(() => {
        function handleWindowResize() {
            let size = getWindowSize();
            setWindowSize(size);

        }

        window.addEventListener('resize', handleWindowResize);

        animationRef.current = anime.timeline({
            easing: 'easeInCubic',
            autoplay: false,
            delay: 0,
            duration: 0
        })
            .add({
                targets: ".contactCTA",
                duration: 100,
                opacity: 0,
                scale: 0.3,
            })
            .add({
                targets: ".solver",
                duration: 400,
                opacity: 1,
            })
            .add({
                targets: [".inputContact", "textarea"],
                backgroundColor: "rgba(0,0,0,0)",
                color: "#fff",
                margin: 0,
                duration: 100,
            })
            .add({
                targets: ".envelopTop",
                zIndex: 2,
                delay: 0,
                duration: 1,
            })
            .add({
                targets: '.triangle',
                rotateX: 180,
                fill: '#4B70B8',
                duration: 600,
                delay: 0,
            })
            .add({
                targets: '.envelop',
                scale: 0.6,
                delay: 100,
                duration: 600,
            })
            .add({
                targets: '.envelop',
                delay: 100,
                duration: 800,
                translateX: '200vw',
                translateY: '-40vh',
                rotateZ: -10,
            })
            .add({
                targets: ".successful",
                duration: 300,
                delay: 300,
                opacity: 1,
                scale: 1.1,
            })
            .add({
                targets: '.envelop',
                delay: 0,
                duration: 1,
                opacity: 0,
            })
            .add({
                targets: '.envelop',
                delay: 100,
                duration: 800,
                translateX: '0vw',
                translateY: '0vh',
                scale: 1,
                rotateZ: 0,
            })
            .add({
                targets: [".inputContact", "textarea"],
                backgroundColor: "#E6E6E6",
                color: "#000",
                margin: "10px 0",
                duration: 100,
            })
            .add({
                targets: ".solver",
                duration: 400,
                opacity: 0,
            })
            .add({
                targets: ".envelopTop",
                zIndex: -1,
                delay: 0,
                duration: 1,
            })
            .add({
                targets: '.triangle',
                rotateX: 0,
                fill: '#252F41',
                duration: 600,
                delay: 0,
            })
            .add({
                targets: ".successful",
                duration: 300,
                delay: 0,
                opacity: 0,
                scale: 0.6,
            })
            .add({
                targets: '.envelop',
                delay: 0,
                duration: 400,
                opacity: 1,
            })
            .add({
                targets: ".contactCTA",
                duration: 400,
                opacity: 1,
                scale: 1,
            })
        return () => {
            window.removeEventListener('resize', handleWindowResize);
        };
    }, []);
    return (
        <div ref={ref} className="contentPage" id="contact" >
            <div className="title">Contact Me</div>
            <div className="envelop">
                <svg className="envelopTop" viewBox="0 0 80 80" preserveAspectRatio="none">
                    <polygon points="0,40 40,0 80,40" className="triangle" />
                </svg>
                <div className="contactContainer">
                    <div className="contactLeft">
                        <input disabled={disableInput} type="text" placeholder="Name" className="inputContact" />
                        <input disabled={disableInput} type="email" placeholder="Email" className="inputContact" />
                        <textarea disabled={disableInput} placeholder="Message..."></textarea>
                    </div>
                    <div className="contactRight">
                        <div className="solver">
                            Charles<br />
                            Front-End developer
                        </div>
                        <div
                            onClick={() => {
                                if (windowSize.innerWidth > 991) {
                                    setDisableInput(true);
                                    animationRef?.current?.play();
                                    setTimeout(() => {
                                        setDisableInput(false);
                                    }, 4400);
                                }
                            }
                            }
                            className="contactCTA"
                            duration={300}
                        >
                            Send
                            <RiSendPlaneLine className="arrowIconSend" size="30" />
                        </div>
                    </div>
                </div>

            </div>
            <div className="successful">
                Your message got successfully sent !
            </div>
        </div >
    )
});

export default Contact;
